const { AzureFunction, Context } = require('@azure/functions');
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey('SG.azure_demo_key_123');

const twilioSid = 'AC1234567890abcdef';
const twilioToken = 'your_twilio_token'; // Replace with your Twilio token
const accountSid = `https://api.twilio.com/2010-04-01/Accounts/${twilioSid}`;

const httpTrigger: AzureFunction = async (context: Context, req: any) => {
    context.log('HTTP trigger function processed a request.');

    const { name, email, phone } = req.body;

    if (!name || !email || !phone) {
        return { status: 400, body: 'Please pass name, email and phone in the request body' };
    }

    try {
        const msg = {
            to: email,
            from: 'your_sendgrid_email@example.com', // Replace with your SendGrid email
            subject: 'Hello from Azure Function!',
            text: `Hello ${name}, this is a test email sent using SendGrid.`
        };

        await sgMail.send(msg);

        const message = {
            from: `${process.env.TWILIO_PHONE_NUMBER}`, // Replace with your Twilio phone number
            to: phone,
            body: `Hello ${name}, this is a test SMS sent using Twilio.`,
            messagingServiceSid: twilioSid
        };

        await fetch(`${accountSid}/Messages.json`, {
            method: 'POST',
            headers: { Authorization: `Bearer ${twilioToken}` },
            body: JSON.stringify(message)
        });

        context.res = { status: 200, body: 'Email and SMS sent successfully' };
    } catch (error) {
        context.log.error(error);
        return { status: 500, body: 'Internal Server Error' };
    }
};

module.exports = httpTrigger;